//switch \u5E26\u8868\u8FBE\u5F0F\uFF0Cswitch n \u8981\u548Ccase \u503C\u76F8\u7B49 \u624D\u4F1A\u6267\u884C\uFF0Ccase \u91CC\u53EF\u4EE5\u8DDF\u591A\u4E2A\u503C\uFF0C\u6BD4\u5982 case 1,2,3: func main() { n := 2 switch n { case 1: fmt.Println("n = ",n) case 2: fmt.Println("n = ",n) case 3: fmt.Println("n = ",n) default: fmt.Println("default case") } } //switch \u5E26\u8868\u8FBE\u5F0F\uFF0C\u901A\u8FC7switch\u505A\u7C7B\u578B\u5224\u65AD func main() { var t interface{} switch t.(type) { case int: fmt.Println("int") case string: fmt.Println("string") case bool: fmt.Println("bool") case float64: fmt.Println("float64") default: fmt.Println("default interface") } } //switch\u901A\u8FC7 fallthrough \u7A7F\u900F\uFF0C\u4E0B\u9762\u7684 n := 2 \uFF0C\u4F1A\u8F93\u51FA\uFF1A 1,2 3,4 5,6 \u53EA\u8981\u9047\u5230 fallthrough \u5C31\u4F1A\u7EE7\u7EED\u5411\u4E0B\u6267\u884C,\u800C\u4E0D\u7BA1\u6761\u4EF6\u6210\u4E0D\u6210\u7ACB func main(){ n := 2 switch n { case 1, 2: fmt.Println("1,2") fallthrough case 3, 4: fmt.Println("3,4") fallthrough case 5, 6: fmt.Println("5,6") fallthrough default: fmt.Println("default case") } } //switch \u4E0D\u5E26\u8868\u8FBE\u5F0F\uFF0C\u8FD9\u79CD\u7528\u6CD5\u76F8\u5F53\u4E8E switch true\uFF0Ccase \u540E\u8868\u8FBE\u5F0F\u4E5F\u8981\u4E3A true \u624D\u4F1A\u6267\u884C func main() { n := 1 switch { case n == 1: fmt.Println("n = ",n) case n == 2: fmt.Println("n = ",n) case n == 3: fmt.Println("n = ",n) default: fmt.Println("default case") } }`}]},{path:"/content/go/base/golang%E4%B9%8B%E5%8D%95%E5%85%83%E6%B5%8B%E8%AF%95%E9%80%9A%E8%BF%87viper%E8%AF%BB%E5%8F%96%E9%85%8D%E7%BD%AE%E6%8A%A5%E9%94%99%E7%9A%84%E9%97%AE%E9%A2%98.html",title:"golang\u4E4B\u5355\u5143\u6D4B\u8BD5\u901A\u8FC7viper\u8BFB\u53D6\u914D\u7F6E\u62A5\u9519\u7684\u95EE\u9898",pathLocale:"/",contents:[{header:"",slug:"",content:`golang\u4E4B\u5355\u5143\u6D4B\u8BD5\u901A\u8FC7viper\u8BFB\u53D6\u914D\u7F6E\u62A5\u9519\u7684\u95EE\u9898
